// lib/auth.ts
import { SignJWT, jwtVerify } from 'jose'

export const ADMIN_SESSION_COOKIE = 'admin_session'
const secret = new TextEncoder().encode(process.env.JWT_SECRET)

export async function signJwt(payload: Record<string, unknown>) {
  return new SignJWT(payload)
    .setProtectedHeader({ alg: 'HS256' })
    .setExpirationTime('1d')
    .sign(secret)
}

export async function verifyJwt(token: string) {
  try {
    const { payload } = await jwtVerify(token, secret)
    return payload
  } catch {
    return null
  }
}

// app/api/auth/login/route.ts
export async function POST(req: Request) {
  const { password } = await req.json()
  if (password !== process.env.ADMIN_PASSWORD) {
    return Response.json({ error: '비밀번호가 올바르지 않습니다.' }, { status: 401 })
  }
  const token = await signJwt({ role: 'admin' })
  const res = Response.json({ ok: true })
  res.headers.set('Set-Cookie', `${ADMIN_SESSION_COOKIE}=${token}; Path=/; HttpOnly; SameSite=Lax; Max-Age=86400`)
  return res
}

// app/api/auth/logout/route.ts
export async function POST() {
  const res = Response.redirect('/admin/login')
  res.headers.set('Set-Cookie', `${ADMIN_SESSION_COOKIE}=; Path=/; HttpOnly; Max-Age=0`)
  return res
}

// middleware.ts (프로젝트 루트)
import { NextRequest, NextResponse } from 'next/server'
import { verifyJwt, ADMIN_SESSION_COOKIE } from '@/lib/auth'

export async function middleware(req: NextRequest) {
  const { pathname } = req.nextUrl
  // 로그인 페이지는 통과
  if (pathname === '/admin/login') return NextResponse.next()

  const token = req.cookies.get(ADMIN_SESSION_COOKIE)?.value
  if (!token || !(await verifyJwt(token))) {
    const loginUrl = new URL('/admin/login', req.url)
    loginUrl.searchParams.set('redirect', pathname)
    return NextResponse.redirect(loginUrl)
  }
  return NextResponse.next()
}

export const config = {
  matcher: ['/admin/:path*']
}

